mapper.select:
select u.user_id, u.user_no, u.nick_name, u.avatar, u.email, u.mobile, u.status, u.invite_code, u.inviter_user_id, u.activate_status, u.activate_time, u.last_login_ip, u.last_login_device, u.last_login_time, u.create_time, u.update_time, group_concat(distinct ua.auth_type order by ua.auth_type separator ',') as auth_types, ifnull(w.balance_power, 0) as balance_power, ifnull(w.total_consume_power, 0) as total_consume_power, ifnull(w.total_give_power, 0) as total_give_power, count(distinct t.task_id) as task_count, count(distinct i.invitee_user_id) as invite_count from ai_c_user u left join ai_c_user_auth ua on ua.user_id = u.user_id left join ai_c_wallet w on w.user_id = u.user_id left join ai_c_task t on t.user_id = u.user_id left join ai_c_user_invite i on i.inviter_user_id = u.user_id
and u.user_id = #{userId} and u.user_no like concat('%', #{userNo}, '%') and u.nick_name like concat('%', #{nickName}, '%') and u.email like concat('%', #{email}, '%') and u.mobile like concat('%', #{mobile}, '%') and u.status = #{status}
group by u.user_id, u.user_no, u.nick_name, u.avatar, u.email, u.mobile, u.status, u.invite_code, u.inviter_user_id, u.activate_status, u.activate_time, u.last_login_ip, u.last_login_device, u.last_login_time, u.create_time, u.update_time, w.balance_power, w.total_consume_power, w.total_give_power order by u.user_id desc
